const now = new Date();
const yesterday = new Date(now.getTime() - 86400000).toISOString();
return [{ json: {
  timestamp: now.toISOString(),
  lookback_from: yesterday,
  lookback_to: now.toISOString(),
  metrics: ['ctr', 'engagement_rate', 'conversion_rate', 'cost_per_conversion', 'creative_angle', 'audience_segment']
} }];

const outcomes = $node['fetch-outcomes'].json.outcomes || [];
const metrics = $node['fetch-metrics'].json.metrics || [];
const aggregated = {};
outcomes.forEach(outcome => {
  const angle = outcome.output?.creative_angle || 'unknown';
  const segment = outcome.output?.audience_segment || 'general';
  const key = `${angle}_${segment}`;
  if (!aggregated[key]) {
    aggregated[key] = {
      angle: angle,
      segment: segment,
      outcome_count: 0,
      avg_ctr: 0,
      avg_engagement: 0,
      total_conversions: 0,
      avg_spend: 0
    };
  }
  aggregated[key].outcome_count += 1;
});
metrics.forEach(m => {
  const angle = m.creative_angle || 'unknown';
  const segment = m.audience_segment || 'general';
  const key = `${angle}_${segment}`;
  if (aggregated[key]) {
    aggregated[key].avg_ctr = (aggregated[key].avg_ctr + parseFloat(m.ctr)) / 2;
    aggregated[key].avg_engagement = (aggregated[key].avg_engagement + parseFloat(m.engagement_rate || 0)) / 2;
    aggregated[key].total_conversions += parseInt(m.conversions) || 0;
    aggregated[key].avg_spend = (aggregated[key].avg_spend + parseFloat(m.spend)) / 2;
  }
});
const sorted = Object.values(aggregated).sort((a, b) => b.avg_ctr - a.avg_ctr);
return [{ json: {
  aggregated_insights: sorted.slice(0, 10),
  total_combos: sorted.length,
  top_performing_angles: sorted.slice(0, 3).map(s => s.angle),
  top_performing_segments: [...new Set(sorted.slice(0, 3).map(s => s.segment))]
} }];

